/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate through all non-empty subsets of nodes.
    // There are 2^n - 1 such subsets. We use bitmasks from 1 to 2^n - 1.
    const numSubsets = 1 << n;
    for (let mask = 1; mask < numSubsets; mask++) {
        // 1. Check if the sum of values in the subset is even.
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        if (sum % 2 !== 0) {
            continue; // Skip if sum is odd
        }

        // 2. Check if the induced subgraph is connected.

        // Identify the nodes in the subset s
        const subsetNodes = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
            }
        }

        if (subsetNodes.length === 0) {
            continue; // Should not happen due to mask starting from 1
        }

        // Use BFS or DFS to check connectivity within the induced subgraph
        const startNode = subsetNodes[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            // Check neighbors of u in the original graph
            for (const v of adj[u]) {
                // Check if v is in the subset AND v has not been visited
                if (((mask >> v) & 1) && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // If the number of reachable nodes equals the total number of nodes in the subset, it is connected.
        if (visitedCount === subsetNodes.length) {
            count++;
        }
    }

    return count;
}

