using namespace std;

long long solve(std::vector<long long> nums, std::vector<std::vector<long long>> edges) {
    int n = nums.size();
    vector<vector<int>> adj(n);
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    long long count = 0;

    // Iterate through all non-empty subsets of nodes using bitmasks.
    int numSubsets = 1 << n;
    for (int mask = 1; mask < numSubsets; ++mask) {
        // 1. Check if the sum of values in the subset is even.
        long long sum = 0;
        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        if (sum % 2 != 0) {
            continue; // Skip if sum is odd
        }

        // 2. Check if the induced subgraph is connected.

        // Identify the nodes in the subset s and count them
        vector<int> subsetNodes;
        for (int i = 0; i < n; ++i) {
            if ((mask >> i) & 1) {
                subsetNodes.push_back(i);
            }
        }

        // subsetNodes.size() is guaranteed to be >= 1 because mask >= 1.
        int subsetSize = subsetNodes.size();
        if (subsetSize == 0) continue;

        // Use BFS to check connectivity within the induced subgraph
        int startNode = subsetNodes[0];
        vector<bool> visited(n, false);
        queue<int> q;

        q.push(startNode);
        visited[startNode] = true;
        int visitedCount = 0;

        while (!q.empty()) {
            int u = q.front();
            q.pop();
            visitedCount++;

            // Check neighbors of u in the original graph
            for (int v : adj[u]) {
                // Check if v is in the subset AND v has not been visited
                // v is in the subset if (mask >> v) & 1 is true
                if (((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    q.push(v);
                }
            }
        }

        // If the number of reachable nodes equals the total number of nodes in the subset, it is connected.
        if (visitedCount == subsetSize) {
            count++;
        }
    }

    return count;
}

